reg [31:0] bank [15:0];
always @(posedge clk) begin
  integer i;
  for (i=0;i<16;i=i+1) bank[i] <= 32'd0;
end

reg [31:0] bank0 [15:0];
reg [31:0] bank1 [15:0];
reg [31:0] bank2 [15:0];
reg [31:0] bank3 [15:0];
always @(posedge clk) begin
  integer i;
  for (i=0;i<16;i=i+1) begin
    bank0[i] <= 32'd0;
    bank1[i] <= 32'd0;
    bank2[i] <= 32'd0;
    bank3[i] <= 32'd0;
  end
end

reg [31:0] bank0 [15:0];
reg [31:0] bank1 [15:0];
reg [3:0] ld_vld;
always @(posedge clk) begin
  integer i;
  for (i=0;i<16;i=i+1) begin
    case (opcode)
      4'd0: begin
        bank0[i] <= 32'd0;
        bank1[i] <= 32'd0;
        case (mode)
          2'd0: ld_vld <= 4'b0001;
          2'd1: ld_vld <= 4'b0010;
          2'd2: ld_vld <= 4'b0100;
          2'd3: ld_vld <= 4'b1000;
        endcase
      end
    endcase
  end
end
